package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetCommentMarker_DefaultIsNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getCommentMarker(), "Default commentMarker should be null");
    }

    @Test
    public void testGetCommentMarker_WithCommentMarkerChar() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        Character commentMarker = format.getCommentMarker();
        assertNotNull(commentMarker, "Comment marker should not be null");
        assertEquals(Character.valueOf('#'), commentMarker, "Comment marker should be '#'");
    }

    @Test
    public void testGetCommentMarker_WithCommentMarkerCharacterObject() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(Character.valueOf(';'));
        Character commentMarker = format.getCommentMarker();
        assertNotNull(commentMarker, "Comment marker should not be null");
        assertEquals(Character.valueOf(';'), commentMarker, "Comment marker should be ';'");
    }

    @Test
    public void testGetCommentMarker_WithCommentMarkerNull() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertNull(format.getCommentMarker(), "Comment marker should be null when explicitly set to null");
    }
}
